+    local procedure ConvertNonDeductibleVATAmountToJobCurrency(GenJnlLine: Record "Gen. Journal Line"): Decimal
+    var
+        JobCurrency: Record Currency;
+        GenJnlCurrency: Record Currency;
+    begin
+        // If Job Currency = Document Currency, return the amount as-is
+        if GenJnlLine."Job Currency Code" = GenJnlLine."Currency Code" then
+            exit(GenJnlLine."Non-Deductible VAT Amount");
+
+        // If Job Currency is empty, it's LCY
+        if GenJnlLine."Job Currency Code" = '' then
+            exit(GenJnlLine."Non-Deductible VAT Amount LCY");
+
+        // If Document Currency is empty, it's LCY
+        if GenJnlLine."Currency Code" = '' then begin
+            // Convert from LCY to Job Currency
+            GetCurrencyRounding(GenJnlLine."Job Currency Code");
+            exit(Round(
